output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?game(ABS(?redSoxScore - ?opponentScore) AS ?margin) WHERE {
  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?game wdt:P154 ?series .
  ?game wdt:P31 wd:Q2895913 .
  {
    ?game wdt:P1898 wd:Q213959 ; wdt:P290 ?redSoxScore ; wdt:P291 ?opponentScore .
  } UNION {
    ?game wdt:P1895 wd:Q213959 ; wdt:P291 ?redSoxScore ; wdt:P290 ?opponentScore .
  }
}
ORDER BY DESC(?margin)
LIMIT 1

