           wdt:P290 ?redSoxScore .
    ?match wdt:P291 ?opponentScore .
  }
  OPTIONAL {
    ?match wdt:P1895 wd:Q213959 ;
           wdt:P291 ?redSoxScore .
    ?match wdt:P290 ?opponentScore .
  }
}
ORDER BY DESC(?margin)
LIMIT 1

SELECT ?match (ABS(?redSoxScore - ?opponentScore) AS ?margin) WHERE {
  VALUES ?series { wd:Q3511178 wd:Q14870260 wd:Q56692089 }
  ?match wdt:P361 ?series .
  ?match wdt:P31 wd:Q2895913 .

  # Red Sox as home team
  OPTIONAL {
    ?match wdt:P1898 wd:Q213959 ;
           wdt:P1350 ?redSoxScore .
    ?match wdt:P1895 ?opponentTeam ;
           wdt:P1350 ?opponentScore .
  }

  # Red Sox as away team
  OPTIONAL {
    ?match wdt:P1895 wd:Q213959 ;
           wdt:P1350 ?redSoxScore .
    ?match wdt:P1898 ?opponentTeam ;
           wdt:P1350 ?opponentScore .
  }
}
ORDER BY DESC(?margin)
LIMIT 1

SELECT ?match (ABS(?redSoxScore - ?opponentScore) AS ?margin) WHERE {
  VALUES ?series { wd:Q3511178 wd:Q14870260 wd:Q56692089 }
  ?series wdt:P154 ?match .
  ?match wdt:P1898 ?homeTeam ;
         wdt:P1895 ?awayTeam ;
         wdt:P290 ?homeScore ;
         wdt:P291 ?awayScore .

  # Red Sox as home team
  FILTER (?homeTeam = wd:Q213959)
  BIND (?homeScore AS ?redSoxScore)
  BIND (?awayScore AS ?opponentScore)

  UNION

  # Red Sox as away team
  FILTER (?awayTeam = wd:Q213959)
  BIND (?awayScore AS ?redSoxScore)
  BIND (?homeScore AS ?opponentScore)
}
ORDER BY DESC(?margin)
LIMIT 1

